diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..2c0b86e99c72 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3552,6 +3552,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
           }
       }
     }
+
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
@@ -3723,6 +3724,44 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       II->addRetAttr(Attribute::getWithAlignment(II->getContext(), MinAlign));
       return II;
     }
+    
+    // Handle funnel shift left/right optimizations
+    if (IID == Intrinsic::fshl || IID == Intrinsic::fshr) {
+      // fshl(x, y, z) = (x << (z % BW)) | (y >> (BW - (z % BW)))
+      // fshr(x, y, z) = (x >> (z % BW)) | (y << (BW - (z % BW)))
+      // When y is 0 for fshl or x is 0 for fshr, this simplifies to a shift.
+      Value *X = II->getArgOperand(0);
+      Value *Y = II->getArgOperand(1);
+      Value *Z = II->getArgOperand(2);
+      
+      if (IID == Intrinsic::fshl && match(Y, m_Zero())) {
+        // fshl(x, 0, z) -> x << (z % BW)
+        Value *Shl = Builder.CreateShl(X, Z);
+        return replaceInstUsesWith(CI, Shl);
+      }
+      if (IID == Intrinsic::fshr && match(X, m_Zero())) {
+        // fshr(0, y, z) -> y >> (z % BW)  (logical right shift)
+        Value *LShr = Builder.CreateLShr(Y, Z);
+        return replaceInstUsesWith(CI, LShr);
+      }
+      
+      // Also handle the commuted patterns for fshl/fshr with swapped X/Y
+      // fshl(0, y, z) -> y >> (BW - (z % BW))
+      // fshr(x, 0, z) -> x << (BW - (z % BW))
+      // These require computing the complementary shift amount.
+      unsigned BitWidth = X->getType()->getScalarSizeInBits();
+      if (IID == Intrinsic::fshl && match(X, m_Zero())) {
+        Value *Sub = Builder.CreateSub(ConstantInt::get(Z->getType(), BitWidth), Z);
+        Value *LShr = Builder.CreateLShr(Y, Sub);
+        return replaceInstUsesWith(CI, LShr);
+      }
+      if (IID == Intrinsic::fshr && match(Y, m_Zero())) {
+        Value *Sub = Builder.CreateSub(ConstantInt::get(Z->getType(), BitWidth), Z);
+        Value *Shl = Builder.CreateShl(X, Sub);
+        return replaceInstUsesWith(CI, Shl);
+      }
+    }
+    
     break;
   }
   default: {
@@ -3753,6 +3792,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

